/*
 ESTRUCTURA DE LA CALCULADORA
*/
// Contenedor principal
const contenedor = document.createElement('div');
Object.assign(contenedor.style, {
    width: '300px',
    backgroundColor: '#fff',
    padding: '15px',
    borderRadius: '10px',
    border: '1px solid #ccc'
});
document.body.appendChild(contenedor);

// Pantalla
const pantalla = document.createElement('div');
Object.assign(pantalla.style, {
    backgroundColor: '#20232a',
    color: 'white',
    padding: '20px',
    marginBottom: '10px',
    textAlign: 'right',
    fontSize: '24px',
    borderRadius: '5px'
});
pantalla.innerText = ''; // Ejemplo
contenedor.appendChild(pantalla);

// Contenedor de botones (4 columnas)
const gridBotones = document.createElement('div');
gridBotones.style.display = 'grid';
gridBotones.style.gridTemplateColumns = 'repeat(4, 1fr)';
gridBotones.style.gap = '8px';
contenedor.appendChild(gridBotones);


//variables de memoria
let tecladoActivado = false;
let valorEnCuadro = "";
let memoria = {};

//Funciones de logica
function actualizarPantalla(valor){
    valorEnCuadro = valor;
    pantalla.innerText = valorEnCuadro;
}

//LISTA - HISTORIAL
const historial = document.createElement('div');
Object.assign(historial.style, {
    marginTop: '20px',
    border: '1px solid #ccc',
    padding: '10px',
    maxHeight: '200px',
    overflowY: 'auto'
});
contenedor.appendChild(historial);

// Función para agregar al historial
function agregarAlHistorial(texto) {
    const fila = document.createElement('div');
    fila.innerText = texto;
    fila.style.borderBottom = '1px solid #eee';
    fila.style.padding = '5px';
    historial.prepend(fila); // prepend pone lo nuevo arriba
}

// Manejo de botones con sus colores
const botones = [
    { text: 'AC', color: '#900000' }, { text: 'C', color: '#ff944dc3' }, { text: '←', color: '#ff944dc3' }, { text: '÷', color: '#4d94ff' },
    { text: '(', color: '#9966ff88' }, { text: ')', color: '#9966ff88' }, { text: 'x', color: '#4d66ff' }, { text: 'y', color: '#4d66ff' },
    { text: '7', color: '#e0e0e0' }, { text: '8', color: '#e0e0e0' }, { text: '9', color: '#e0e0e0' }, { text: '×', color: '#4d94ff' },
    { text: '4', color: '#e0e0e0' }, { text: '5', color: '#e0e0e0' }, { text: '6', color: '#e0e0e0' }, { text: '-', color: '#4d94ff' },
    { text: '1', color: '#e0e0e0' }, { text: '2', color: '#e0e0e0' }, { text: '3', color: '#e0e0e0' }, { text: '+', color: '#4d94ff' },
    { text: '0', color: '#e0e0e0' }, { text: '.', color: '#e0e0e0' }, { text: '=', color: '#00cc99' }, { text: 'Evaluar', color: '#00cc99' }
];

botones.forEach(btnData => {
    const btn = document.createElement('button');
    btn.innerText = btnData.text;
    btn.style.backgroundColor = btnData.color;
    btn.style.border = 'none';
    btn.style.padding = '15px';
    btn.style.borderRadius = '5px';
    btn.style.cursor = 'pointer';

    //Logica de botones

    btn.onclick = () => {

        if (!tecladoActivado) return;
        const valor = btn.innerText.trim();

        if(valor === 'AC'){
            actualizarPantalla("");
            historial.innerHTML = "";
            memoria = {};
            tecladoActivado = false;
        }else if(valor === '←'){
            actualizarPantalla(valorEnCuadro.slice(0, -1));
        }else if(valor === 'C'){
            actualizarPantalla("");

        }else if (valor === '=') {
            actualizarPantalla(valorEnCuadro + "=");
        }else if(valor === 'Evaluar'){
            try {
                let expresion = valorEnCuadro.trim();

                if (expresion.includes('=')) {
                    // ASIGNACIÓN
                    const partes = expresion.split('=');
                    const variable = partes[0].trim();
                    const valorAsignado = Number(eval(partes[1].replace(/×/g, '*').replace(/÷/g, '/')));
                    
                    memoria[variable] = valorAsignado;

                    // AGREGAMOS AL HISTORIAL
                    agregarAlHistorial(variable + " = " + valorAsignado);
                    actualizarPantalla("");
                } else {
                    // CÁLCULO
                    let expresionLista = expresion
                        .replace(/×/g, '*')
                        .replace(/÷/g, '/')
                        
                        for (let key in memoria) {
                            // Usamos una expresión regular global para reemplazar todas las apariciones
                            let regex = new RegExp('\\b' + key + '\\b', 'g');
                            expresionLista = expresionLista.replace(regex, memoria[key]);
                        }

                    const resultado = eval(expresionLista);
                    agregarAlHistorial(expresion + " = " + resultado);
                    actualizarPantalla(String(resultado));
                    
                }
                tecladoActivado = false;
            } catch (e) {
                actualizarPantalla("ERROR");
                tecladoActivado = false;
            }
        }else{
            actualizarPantalla(valorEnCuadro + valor);
        }
    }


    gridBotones.appendChild(btn);
});

// Botón "Ingresar" aparte (ocupa todo el ancho)
const btnIngresar = document.createElement('button');
btnIngresar.innerText = 'Ingresar';
Object.assign(btnIngresar.style, {
    width: '100%',
    marginTop: '10px',
    padding: '15px',
    backgroundColor: '#333',
    color: 'white',
    border: 'none',
    borderRadius: '5px'
});

btnIngresar.onclick = () => {
    tecladoActivado = true; // Al presionar, habilitamos el teclado
    pantalla.innerText = "Digite su calculo"; // Aviso visual
    valorEnCuadro = ""; // Limpiamos para empezar a escribir
};

contenedor.appendChild(btnIngresar);




